## Context

The project is a Node.js CLI tool (TypeScript, native node:test runner, no jest/vitest).

### Problem
`test/resolve.test.ts` has two weaknesses:
1. **Cross-platform path tests** use `if (process.platform === "win32")` branches — the Windows path assertions are never executed on macOS/Linux and vice versa.
2. **sudo/home lookup tests** actually run real system commands (getent, dscl) against the host machine rather than mocking them.

### Relevant source files

**`src/core/resolve.ts`** — the file under test:
```typescript
import { execFileSync } from "node:child_process";
import { readFileSync } from "node:fs";
import os from "node:os";
import path from "node:path";
import { UserError } from "../errors.ts";
import type { AgentConfig } from "../types.ts";

export function resolveHome(): string {
  if (process.platform === "win32") { return os.homedir(); }
  const sudoUser = process.env["SUDO_USER"];
  if (sudoUser) { return lookupHomeForUser(sudoUser); }
  return os.homedir();
}

function lookupHomeForUser(username: string): string {
  // Method 1: getent passwd (Linux/POSIX, non-darwin only)
  if (process.platform !== "darwin") {
    try {
      const out = execFileSync("getent", ["passwd", username], {encoding:"utf8",stdio:["ignore","pipe","ignore"]}).trim();
      const home = out.split(":")[5];
      if (typeof home === "string" && home.startsWith("/")) return home;
    } catch { /* fall through */ }
  }

  // Method 2: dscl (macOS only)
  if (process.platform === "darwin") {
    try {
      const out = execFileSync("dscl", [".", "-read", `/Users/${username}`, "NFSHomeDirectory"], {encoding:"utf8",stdio:["ignore","pipe","ignore"]}).trim();
      const home = out.replace(/^NFSHomeDirectory:\s*/, "").trim();
      if (home.startsWith("/")) return home;
    } catch { /* fall through */ }
  }

  // Method 3: /etc/passwd fallback (all POSIX)
  try {
    const passwd = readFileSync("/etc/passwd", "utf8");
    for (const line of passwd.split("\n")) {
      const parts = line.split(":");
      if (parts[0] === username) {
        const home = parts[5];
        if (typeof home === "string" && home.startsWith("/")) return home;
      }
    }
  } catch { /* fall through */ }

  throw new UserError("RESOLVE_FAILED", `Cannot determine home directory for user "${username}". ...`);
}

export function getPlatformKey(): "posix" | "windows" {
  return process.platform === "win32" ? "windows" : "posix";
}

export function resolveAgentSkillPath(agent: AgentConfig, skillName: string, home: string): string {
  const platform = getPlatformKey();
  const template = agent.skills[platform];
  return resolvePlaceholders(template, skillName, home);
}

export function resolveAgentDetectPath(agent: AgentConfig, home: string): string {
  const platform = getPlatformKey();
  const template = agent.detectPaths[platform];
  return resolvePlaceholders(template, "", home);
}

// PRIVATE — NOT exported
function resolvePlaceholders(segments: string[], skillName: string, home: string): string {
  const appdata = process.env["APPDATA"] ?? path.join(home, "AppData", "Roaming");
  const resolved = segments.map(seg =>
    seg.replace("{home}", home).replace("{name}", skillName).replace("{appdata}", appdata)
  );
  return path.join(...resolved);
}
```

**`src/config/agents.ts`** — agent registry:
