  { id: "opencode",        skills: { posix: ["{home}",".config","opencode","skills","{name}"],  windows: ["{appdata}","opencode","skills","{name}"] }, detectPaths: { posix: ["{home}",".config","opencode"], windows: ["{appdata}","opencode"] }, detectBinary: "opencode" },
