     1→import { execFileSync } from "node:child_process";
     2→import { readFileSync } from "node:fs";
     3→import os from "node:os";
     4→import path from "node:path";
     5→import { UserError } from "../errors.ts";
     6→import type { AgentConfig } from "../types.ts";
     7→
     8→export function resolveHome(): string {
     9→  if (process.platform === "win32") {
    10→    return os.homedir();
    11→  }
    12→
    13→  const sudoUser = process.env["SUDO_USER"];
    14→  if (sudoUser) {
    15→    return lookupHomeForUser(sudoUser);
    16→  }
    17→
    18→  return os.homedir();
    19→}
    20→
    21→function lookupHomeForUser(username: string): string {
    22→  // Method 1: getent passwd (Linux/POSIX — handles LDAP, NIS, local via NSS)
    23→  if (process.platform !== "darwin") {
    24→    try {
    25→      const out = execFileSync("getent", ["passwd", username], {
    26→        encoding: "utf8",
    27→        stdio: ["ignore", "pipe", "ignore"],
    28→      }).trim();
    29→      const home = out.split(":")[5];
    30→      if (typeof home === "string" && home.startsWith("/")) return home;
    31→    } catch {
    32→      // getent unavailable or user not found — try next method
    33→    }
    34→  }
    35→
    36→  // Method 2: dscl (macOS directory services)
    37→  if (process.platform === "darwin") {
    38→    try {
    39→      const out = execFileSync(
    40→        "dscl",
    41→        [".", "-read", `/Users/${username}`, "NFSHomeDirectory"],
    42→        { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] }
    43→      ).trim();
    44→      const home = out.replace(/^NFSHomeDirectory:\s*/, "").trim();
    45→      if (home.startsWith("/")) return home;
    46→    } catch {
    47→      // dscl unavailable or user record not found — try next method
    48→    }
    49→  }
    50→
    51→  // Method 3: parse /etc/passwd directly (universal POSIX fallback)
    52→  try {
    53→    const passwd = readFileSync("/etc/passwd", "utf8");
    54→    for (const line of passwd.split("\n")) {
    55→      const parts = line.split(":");
    56→      if (parts[0] === username) {
    57→        const home = parts[5];
    58→        if (typeof home === "string" && home.startsWith("/")) return home;
    59→      }
    60→    }
    61→  } catch {
    62→    // /etc/passwd unavailable — fall through to error
    63→  }
    64→
    65→  throw new UserError(
    66→    "RESOLVE_FAILED",
    67→    `Cannot determine home directory for user "${username}". ` +
    68→      `Tried getent, dscl, and /etc/passwd. ` +
    69→      `Run without sudo, or set HOME to the correct path before invoking with sudo.`
    70→  );
    71→}
    72→
    73→export function getPlatformKey(): "posix" | "windows" {
    74→  return process.platform === "win32" ? "windows" : "posix";
    75→}
    76→
    77→export function getDeployMethod(): "symlink" | "copy" {
    78→  return process.platform === "win32" ? "copy" : "symlink";
    79→}
    80→
    81→export function resolveAgentSkillPath(
    82→  agent: AgentConfig,
    83→  skillName: string,
    84→  home: string
    85→): string {
    86→  const platform = getPlatformKey();
    87→  const template = agent.skills[platform];
    88→  return resolvePlaceholders(template, skillName, home);
    89→}
    90→
    91→export function resolveAgentDetectPath(
    92→  agent: AgentConfig,
    93→  home: string
    94→): string {
    95→  const platform = getPlatformKey();
    96→  const template = agent.detectPaths[platform];
    97→  return resolvePlaceholders(template, "", home);
    98→}
    99→
   100→function resolvePlaceholders(
   101→  segments: string[],
   102→  skillName: string,
   103→  home: string
   104→): string {
   105→  const appdata = process.env["APPDATA"] ?? path.join(home, "AppData", "Roaming");
   106→  const resolved = segments.map((seg) =>
   107→    seg
   108→      .replace("{home}", home)
   109→      .replace("{name}", skillName)
   110→      .replace("{appdata}", appdata)
   111→  );
   112→  return path.join(...resolved);
   113→}
