    10→export async function detectInstalledAgents(home: string): Promise<AgentId[]> {
    11→  const detected: AgentId[] = [];
    12→
    13→  for (const agent of AGENT_REGISTRY) {
    14→    if (await isAgentInstalled(agent, home)) {
    15→      detected.push(agent.id);
    16→    }
    17→  }
    18→
    19→  return detected;
    20→}
    21→
    22→async function isAgentInstalled(agent: AgentConfig, home: string): Promise<boolean> {
    23→  const detectPath = resolveAgentDetectPath(agent, home);
    24→  try {
    25→    await access(detectPath);
    26→    return true;
    27→  } catch {}
    28→
    29→  if (agent.detectBinary) {
    30→    return isBinaryInPath(agent.detectBinary);
    31→  }
    32→
    33→  return false;
    34→}
    35→
    36→async function isBinaryInPath(binary: string): Promise<boolean> {
    37→  if (process.platform === "win32") {
    38→    try {
    39→      await execFileAsync("where.exe", [binary]);
    40→      return true;
    41→    } catch {
    42→      return false;
    43→    }
    44→  }
    45→
    46→  try {
    47→    await execFileAsync("which", [binary]);
    48→    return true;
    49→  } catch (err: unknown) {
    50→    // `which` itself is not installed — fall back to the POSIX shell built-in
    51→    if (isENOENT(err)) {
    52→      return isBinaryViaCommandV(binary);
    53→    }
    54→    return false;
    55→  }
    56→}
    57→
    58→// Used only when `which` is absent (e.g. minimal Alpine containers).
    59→// `command -v` is a POSIX shell built-in available wherever /bin/sh is.
    60→async function isBinaryViaCommandV(binary: string): Promise<boolean> {
    61→  try {
    62→    // Pass binary as a positional arg ($1) to avoid any shell-injection risk.
    63→    await execFileAsync("sh", ["-c", 'command -v "$1"', "--", binary]);
    64→    return true;
    65→  } catch {
    66→    return false;
    67→  }
    68→}
    69→
    70→function isENOENT(err: unknown): boolean {
    71→  return (
    72→    typeof err === "object" &&
    73→    err !== null &&
    74→    (err as NodeJS.ErrnoException).code === "ENOENT"
    75→  );
    76→}
