     8→export function planRevert(
     9→  manifest: Manifest,
    10→  detectedAgents: AgentId[],
    11→  home: string
    12→): RevertAction[] {
    13→  const actions: RevertAction[] = [];
    14→
    15→  for (const skill of manifest.skills) {
    16→    for (const agentId of skill.agents) {
    17→      if (!detectedAgents.includes(agentId)) continue;
    18→
    19→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    20→      if (!agent) continue;
    21→
    22→      const target = resolveAgentSkillPath(agent, skill.name, home);
